export function getFilterFn<TData>(): FilterFn<TData> {
	return (row: Row<TData>, columnId: string, filterValue: unknown): boolean => {
		if (!filterValue || typeof filterValue !== 'object') {
			return true;
		}

		const filter = filterValue as FilterValue;
		const { operator, value, endValue } = filter;

		const cellValue = row.getValue(columnId);

		if (operator === 'isEmpty') {
			return (
				cellValue === null ||
				cellValue === undefined ||
				cellValue === '' ||
				(Array.isArray(cellValue) && cellValue.length === 0)
			);
		}

		if (operator === 'isNotEmpty') {
			return !(
				cellValue === null ||
				cellValue === undefined ||
				cellValue === '' ||
				(Array.isArray(cellValue) && cellValue.length === 0)
			);
		}

		if (operator === 'isTrue') {
			return cellValue === true;
		}

		if (operator === 'isFalse') {
			return cellValue === false || !cellValue;
		}

		if (value === undefined || value === null || value === '') {
			return true;
		}

		const cellValueStr = String(cellValue ?? '').toLowerCase();
		const filterValueStr = typeof value === 'string' ? value.toLowerCase() : String(value);

		if (operator === 'contains') {
			return cellValueStr.includes(filterValueStr);
		}

		if (operator === 'notContains') {
			return !cellValueStr.includes(filterValueStr);
		}

		if (operator === 'equals') {
			if (typeof cellValue === 'number' && typeof value === 'number') {
				return cellValue === value;
			}
			if (cellValue instanceof Date && typeof value === 'string') {
				const cellDate = new Date(cellValue);
				const filterDate = new Date(value);
				return cellDate.toDateString() === filterDate.toDateString();
			}
			return cellValueStr === filterValueStr;
		}

		if (operator === 'notEquals') {
			if (typeof cellValue === 'number' && typeof value === 'number') {
				return cellValue !== value;
			}
			if (cellValue instanceof Date && typeof value === 'string') {
				const cellDate = new Date(cellValue);
				const filterDate = new Date(value);
				return cellDate.toDateString() !== filterDate.toDateString();
			}
			return cellValueStr !== filterValueStr;
		}

		if (operator === 'startsWith') {
			return cellValueStr.startsWith(filterValueStr);
		}

		if (operator === 'endsWith') {
			return cellValueStr.endsWith(filterValueStr);
		}

		if (typeof cellValue === 'number' && typeof value === 'number') {
			if (operator === 'greaterThan') {
				return cellValue > value;
			}

			if (operator === 'greaterThanOrEqual') {
				return cellValue >= value;
			}

			if (operator === 'lessThan') {
				return cellValue < value;
			}

			if (operator === 'lessThanOrEqual') {
				return cellValue <= value;
			}

			if (operator === 'isBetween' && typeof endValue === 'number') {
				return cellValue >= value && cellValue <= endValue;
			}
		}

		if (cellValue instanceof Date || typeof cellValue === 'string') {
			const cellDate = new Date(cellValue);
			if (!Number.isNaN(cellDate.getTime()) && typeof value === 'string') {
				const filterDate = new Date(value);

				if (operator === 'before') {
					return cellDate < filterDate;
				}

				if (operator === 'after') {
					return cellDate > filterDate;
				}

				if (operator === 'onOrBefore') {
					return cellDate <= filterDate;
				}

				if (operator === 'onOrAfter') {
					return cellDate >= filterDate;
				}

				if (operator === 'isBetween' && typeof endValue === 'string') {
					const filterDate2 = new Date(endValue);
					return cellDate >= filterDate && cellDate <= filterDate2;
				}
			}
		}

		if (operator === 'is') {
			if (Array.isArray(cellValue)) {
				return cellValue.some((v) => String(v) === String(value));
			}
			return String(cellValue) === String(value);
		}

		if (operator === 'isNot') {
			if (Array.isArray(cellValue)) {
				return !cellValue.some((v) => String(v) === String(value));
			}
			return String(cellValue) !== String(value);
		}

		if (operator === 'isAnyOf' && Array.isArray(value)) {
			if (Array.isArray(cellValue)) {
				return cellValue.some((v) => value.some((fv) => String(v) === String(fv)));
			}
			return value.some((fv) => String(cellValue) === String(fv));
		}

		if (operator === 'isNoneOf' && Array.isArray(value)) {
			if (Array.isArray(cellValue)) {
				return !cellValue.some((v) => value.some((fv) => String(v) === String(fv)));
			}
			return !value.some((fv) => String(cellValue) === String(fv));
		}

		return true;
	};
}

export function formatDate(
	value: Date | string | number | undefined,
	options: Intl.DateTimeFormatOptions = {
		month: 'short',
		day: 'numeric',
		year: 'numeric'
	}
): string {
	if (value === undefined || value === null || value === '') {
		return '';
	}

	const date = value instanceof Date ? value : new Date(value);
	if (Number.isNaN(date.getTime())) {
		return '';
	}

	return new Intl.DateTimeFormat(undefined, options).format(date);
}

export function generateId({ length = 8 }: { length?: number } = {}): string {
	const alphabet = '0123456789abcdefghijklmnopqrstuvwxyz';

	if (typeof crypto !== 'undefined' && typeof crypto.getRandomValues === 'function') {
		const values = new Uint8Array(length);
		crypto.getRandomValues(values);
		return Array.from(values, (value) => alphabet[value % alphabet.length]).join('');
	}

	return Array.from({ length }, () => alphabet[Math.floor(Math.random() * alphabet.length)]).join(
		''
	);
}

import { dataTableConfig } from '$lib/config/data-table.js';
import type {
	ExtendedColumnFilter,
	ExtendedColumnSort,
	FilterVariant
} from '$lib/types/data-table.js';

export interface StateParser<T> {
	parse: (value: string) => T | null;
	serialize: (value: T) => string;
	eq: (left: T, right: T) => boolean;
}

export type FilterItemSchema = {
	id: string;
	value: string | string[];
	variant: FilterVariant;
	operator: (typeof dataTableConfig.operators)[number];
	filterId: string;
};

function getValidKeys(columnIds?: string[] | Set<string>): Set<string> | null {
	if (!columnIds) return null;
	return columnIds instanceof Set ? columnIds : new Set(columnIds);
}

function isSortingItem<TData>(
	item: unknown,
	validKeys: Set<string> | null
): item is ExtendedColumnSort<TData> {
	if (typeof item !== 'object' || item === null) return false;

	const candidate = item as { id?: unknown; desc?: unknown };
	return (
		typeof candidate.id === 'string' &&
		typeof candidate.desc === 'boolean' &&
		(!validKeys || validKeys.has(candidate.id))
	);
}

function isFilterItem<TData>(
	item: unknown,
	validKeys: Set<string> | null,
	validVariants: Set<string>,
	validOperators: Set<string>
): item is ExtendedColumnFilter<TData> {
	if (typeof item !== 'object' || item === null) return false;

	const candidate = item as {
		id?: unknown;
		value?: unknown;
		filterId?: unknown;
		variant?: unknown;
		operator?: unknown;
	};
	return (
		typeof candidate.id === 'string' &&
		(!validKeys || validKeys.has(candidate.id)) &&
		(typeof candidate.value === 'string' ||
			(Array.isArray(candidate.value) &&
				candidate.value.every((entry: unknown) => typeof entry === 'string'))) &&
		typeof candidate.filterId === 'string' &&
		typeof candidate.variant === 'string' &&
		validVariants.has(candidate.variant) &&
		typeof candidate.operator === 'string' &&
		validOperators.has(candidate.operator)
	);
}

export function getSortingStateParser<TData>(
	columnIds?: string[] | Set<string>
): StateParser<ExtendedColumnSort<TData>[]> {
	const validKeys = getValidKeys(columnIds);

	return {
		parse: (value) => {
			try {
				const parsed = JSON.parse(value);
				if (!Array.isArray(parsed)) return null;

				const sorting = parsed as unknown[];
				if (!sorting.every((item) => isSortingItem<TData>(item, validKeys))) return null;

				return sorting;
			} catch {
				return null;
			}
		},
		serialize: (value) => JSON.stringify(value),
		eq: (left, right) =>
			left.length === right.length &&
			left.every((item, index) => item.id === right[index]?.id && item.desc === right[index]?.desc)
	};
}

export function getFiltersStateParser<TData>(
	columnIds?: string[] | Set<string>
): StateParser<ExtendedColumnFilter<TData>[]> {
	const validKeys = getValidKeys(columnIds);
	const validVariants = new Set<string>(dataTableConfig.filterVariants);
	const validOperators = new Set<string>(dataTableConfig.operators);

	return {
		parse: (value) => {
			try {
				const parsed = JSON.parse(value);
				if (!Array.isArray(parsed)) return null;

				const filters = parsed as unknown[];
				if (
					!filters.every((item) =>
						isFilterItem<TData>(item, validKeys, validVariants, validOperators)
					)
				) {
					return null;
				}

				return filters;
			} catch {
				return null;
			}
		},
		serialize: (value) => JSON.stringify(value),
		eq: (left, right) =>
			left.length === right.length &&
			left.every((filter, index) => {
				const rightFilter = right[index];
				if (!rightFilter) return false;

				const leftValue = Array.isArray(filter.value) ? filter.value.join('\u0000') : filter.value;
				const rightValue = Array.isArray(rightFilter.value)
					? rightFilter.value.join('\u0000')
					: rightFilter.value;

				return (
					filter.id === rightFilter.id &&
					leftValue === rightValue &&
					filter.variant === rightFilter.variant &&
					filter.operator === rightFilter.operator &&
					filter.filterId === rightFilter.filterId
				);
			})
	};
}

